def build(item, c):
 rows=R(item); k=lambda d: rows[d]; e=lambda d,t: {'kline':k(d),'evidence':t}
 out={'code':item['code'],'name':item['name'],'market_context':ctx}
 out['volume_price_relation']={'result':c['vpr'],'data':[e(*x) for x in c['vpr_data']],'refs':base_refs['vpr']}
 out['direction']={'result':c['dir'],'data':[e(*x) for x in c['dir_data']],'refs':base_refs['dir']}
 out['anomaly_test_confirmation']={'result':c['atc_result'],'data':[{'role':role,**e(d,t)} for role,d,t in c['atc_data']],'refs':base_refs['atc']}
 out['smart_money']={'result':c['smart'],'data':[e(*x) for x in c['smart_data']],'refs':base_refs['smart']}
 out['reversal']={'result':c['rev'],'data':[e(*x) for x in c['rev_data']],'refs':base_refs['rev']}
 out['key_price']={'result':c['key'],'data':[e(*x) for x in c['key_data']],'refs':base_refs['key']}
 out['chip']={'result':c['chip_result'],'data':{'chip':item['chip'],'kline_evidence':[e(*x) for x in c['chip_data']]},'refs':base_refs['chip']}
 p=generate_report_bundle(out,'thesis')
 print(json.dumps({'code':item['code'],'data_path':str(p['data_path'].resolve()),'report_path':str(p['report_path'].resolve())},ensure_ascii=False))

